import subprocess
import re
import os

def collecter_connexions():
    """Collecte les connexions réseau actives."""
    connexions = []
    try:
        if os.name == "nt":
            result = subprocess.run(
                ["netstat", "-ano"],
                capture_output=True, text=True, timeout=15
            )
        else:
            result = subprocess.run(
                ["ss", "-tnp"],
                capture_output=True, text=True
            )

        # Parser les lignes
        pattern = re.compile(
            r"(TCP|UDP)\s+(\S+):(\d+)\s+(\S+):(\d+)\s+(\S+)(?:\s+(\d+))?",
            re.I
        )
        for ligne in result.stdout.splitlines():
            m = pattern.search(ligne)
            if m:
                connexions.append({
                    "protocole": m.group(1),
                    "local_ip":  m.group(2),
                    "local_port": m.group(3),
                    "remote_ip":  m.group(4),
                    "remote_port": m.group(5),
                    "etat":       m.group(6),
                    "pid":        m.group(7) or "N/A"
                })
    except Exception as e:
        connexions.append({"error": str(e)})

    return connexions

conns = collecter_connexions()[:5]
for c in conns:
    if "error" not in c:
        print(f"{c['protocole']} {c['local_ip']}:{c['local_port']} → {c['remote_ip']}:{c['remote_port']} [{c['etat']}]")
